from datetime import datetime, timezone
from typing import IO
from ..models import ScanReport, PortStatus

class HTMLFormatter:

    def format(self, report: ScanReport, file: IO) -> None:
        html_content = self._generate_html(report)
        file.write(html_content)

    def _generate_html(self, report: ScanReport) -> str:
        total_hosts = len(report.hosts)
        active_hosts = sum((1 for h in report.hosts.values() if any((p.status == PortStatus.OPEN for p in h.ports))))
        total_open_ports = sum((sum((1 for p in h.ports if p.status == PortStatus.OPEN)) for h in report.hosts.values()))
        hosts_html = ''
        for ip, host in report.hosts.items():
            hostname_str = f" <span class='hostname'>({host.hostname})</span>" if host.hostname else ''
            ports_rows = ''
            open_ports = [p for p in host.ports if p.status == PortStatus.OPEN]
            if not open_ports:
                ports_rows = '\n                <tr>\n                    <td colspan="7" class="empty-state">No open ports found on this host.</td>\n                </tr>\n                '
            else:
                for p in sorted(open_ports, key=lambda x: x.port):
                    product = p.product or '-'
                    version = p.version or '-'
                    conf_class = ''
                    conf_text = '-'
                    if p.confidence > 0:
                        conf_text = f'{p.confidence:.0f}%'
                        if p.confidence >= 80:
                            conf_class = 'conf-high'
                        elif p.confidence >= 50:
                            conf_class = 'conf-medium'
                        else:
                            conf_class = 'conf-low'
                    tls_row = ''
                    if p.tls_info:
                        tls_row = f"""\n                        <tr class="tls-row">\n                            <td></td>\n                            <td colspan="6">\n                                <div class="tls-card">\n                                    <div class="tls-title">\n                                        <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><rect x="3" y="11" width="18" height="11" rx="2" ry="2"></rect><path d="M7 11V7a5 5 0 0 1 10 0v4"></path></svg>\n                                        TLS Certificate Info\n                                    </div>\n                                    <div class="tls-grid">\n                                        <div><strong>Version:</strong> {p.tls_info.tls_version or 'Unknown'}</div>\n                                        <div><strong>Cipher:</strong> {p.tls_info.cipher_suite or 'Unknown'}</div>\n                                        <div class="tls-full-width"><strong>Subject:</strong> {p.tls_info.subject or 'Unknown'}</div>\n                                        <div class="tls-full-width"><strong>Issuer:</strong> {p.tls_info.issuer or 'Unknown'}</div>\n                                        {(f"<div class='tls-full-width'><strong>SANs:</strong> {', '.join(p.tls_info.sans)}</div>" if p.tls_info.sans else '')}\n                                    </div>\n                                </div>\n                            </td>\n                        </tr>\n                        """
                    rtt_text = f'{p.rtt * 1000:.1f} ms' if p.rtt is not None else '-'
                    ports_rows += f'\n                    <tr class="port-row">\n                        <td class="port-number">{p.port}</td>\n                        <td class="protocol-cell"><span class="proto-badge {p.protocol.value.lower()}">{p.protocol.value}</span></td>\n                        <td><span class="status-badge open">open</span></td>\n                        <td class="service-name">{p.service_name}</td>\n                        <td>{product}</td>\n                        <td>{version}</td>\n                        <td><span class="conf-badge {conf_class}">{conf_text}</span></td>\n                    </tr>\n                    {tls_row}\n                    '
            hosts_html += f"""\n            <div class="card host-card">\n                <div class="host-header">\n                    <div class="host-info">\n                        <svg class="host-icon" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><rect x="2" y="2" width="20" height="8" rx="2" ry="2"></rect><rect x="2" y="14" width="20" height="8" rx="2" ry="2"></rect><line x1="6" y1="6" x2="6.01" y2="6"></line><line x1="6" y1="18" x2="6.01" y2="18"></line></svg>\n                        <h3>{ip}{hostname_str}</h3>\n                    </div>\n                    {(f"<span class='os-badge'>OS: {host.os_guess}</span>" if host.os_guess else '')}\n                </div>\n                <div class="table-container">\n                    <table>\n                        <thead>\n                            <tr>\n                                <th>Port</th>\n                                <th>Protocol</th>\n                                <th>Status</th>\n                                <th>Service</th>\n                                <th>Product</th>\n                                <th>Version</th>\n                                <th>Confidence</th>\n                            </tr>\n                        </thead>\n                        <tbody>\n                            {ports_rows}\n                        </tbody>\n                    </table>\n                </div>\n            </div>\n            """
        return f"""<!DOCTYPE html>\n<html lang="en">\n<head>\n    <meta charset="UTF-8">\n    <meta name="viewport" content="width=device-width, initial-scale=1.0">\n    <title>NetProbe Scan Report — {(report.targets[0] if report.targets else 'Recon')}</title>\n    <link rel="preconnect" href="https://fonts.googleapis.com">\n    <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>\n    <link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&family=JetBrains+Mono:wght@400;500&display=swap" rel="stylesheet">\n    <style>\n        :root {{\n            --bg-color: #0b0f19;\n            --card-bg: rgba(22, 28, 45, 0.4);\n            --card-border: rgba(255, 255, 255, 0.08);\n            --primary-gradient: linear-gradient(135deg, #6366f1 0%, #3b82f6 100%);\n            --accent-glow: 0 0 20px rgba(99, 102, 241, 0.15);\n            --text-main: #f3f4f6;\n            --text-muted: #9ca3af;\n            --text-dark: #4b5563;\n            --open-color: #10b981;\n            --open-bg: rgba(16, 185, 129, 0.12);\n            --closed-color: #ef4444;\n            --closed-bg: rgba(239, 68, 68, 0.12);\n            --filtered-color: #f59e0b;\n            --filtered-bg: rgba(245, 158, 11, 0.12);\n            --font-main: 'Inter', sans-serif;\n            --font-mono: 'JetBrains Mono', monospace;\n        }}\n\n        * {{\n            box-sizing: border-box;\n            margin: 0;\n            padding: 0;\n        }}\n\n        body {{\n            background-color: var(--bg-color);\n            color: var(--text-main);\n            font-family: var(--font-main);\n            line-height: 1.5;\n            padding: 2rem 1.5rem;\n            min-height: 100vh;\n            background-image:\n                radial-gradient(circle at 10% 20%, rgba(99, 102, 241, 0.05) 0%, transparent 40%),\n                radial-gradient(circle at 90% 80%, rgba(59, 130, 246, 0.05) 0%, transparent 40%);\n            background-attachment: fixed;\n        }}\n\n        .container {{\n            max-width: 1200px;\n            margin: 0 auto;\n        }}\n\n        /* Header styling */\n        header {{\n            margin-bottom: 2.5rem;\n            display: flex;\n            justify-content: space-between;\n            align-items: center;\n            flex-wrap: wrap;\n            gap: 1.5rem;\n        }}\n\n        .brand-section {{\n            display: flex;\n            align-items: center;\n            gap: 0.75rem;\n        }}\n\n        .logo {{\n            width: 40px;\n            height: 40px;\n            background: var(--primary-gradient);\n            border-radius: 12px;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            box-shadow: var(--accent-glow);\n        }}\n\n        .logo svg {{\n            color: #fff;\n        }}\n\n        .brand-name h1 {{\n            font-size: 1.5rem;\n            font-weight: 700;\n            letter-spacing: -0.025em;\n            background: linear-gradient(to right, #fff 40%, #a5b4fc 100%);\n            -webkit-background-clip: text;\n            -webkit-text-fill-color: transparent;\n        }}\n\n        .brand-name span {{\n            font-size: 0.75rem;\n            color: var(--text-muted);\n            font-family: var(--font-mono);\n        }}\n\n        .meta-info {{\n            text-align: right;\n        }}\n\n        .meta-info p {{\n            font-size: 0.875rem;\n            color: var(--text-muted);\n        }}\n\n        .meta-info code {{\n            background-color: rgba(255, 255, 255, 0.05);\n            padding: 0.2rem 0.5rem;\n            border-radius: 4px;\n            font-family: var(--font-mono);\n            font-size: 0.75rem;\n        }}\n\n        /* Dashboard Overview Grid */\n        .overview-grid {{\n            display: grid;\n            grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));\n            gap: 1.5rem;\n            margin-bottom: 3rem;\n        }}\n\n        .card {{\n            background: var(--card-bg);\n            border: 1px solid var(--card-border);\n            border-radius: 16px;\n            backdrop-filter: blur(10px);\n            padding: 1.5rem;\n            transition: transform 0.2s ease, border-color 0.2s ease;\n        }}\n\n        .card:hover {{\n            border-color: rgba(99, 102, 241, 0.3);\n        }}\n\n        .stat-card {{\n            display: flex;\n            flex-direction: column;\n            gap: 0.5rem;\n        }}\n\n        .stat-label {{\n            font-size: 0.875rem;\n            color: var(--text-muted);\n            text-transform: uppercase;\n            letter-spacing: 0.05em;\n        }}\n\n        .stat-value {{\n            font-size: 2.25rem;\n            font-weight: 700;\n            color: #fff;\n        }}\n\n        .stat-desc {{\n            font-size: 0.75rem;\n            color: var(--text-muted);\n        }}\n\n        /* Host section */\n        .host-card {{\n            margin-bottom: 2rem;\n            padding: 0;\n            overflow: hidden;\n        }}\n\n        .host-header {{\n            background: rgba(255, 255, 255, 0.02);\n            border-bottom: 1px solid var(--card-border);\n            padding: 1.25rem 1.5rem;\n            display: flex;\n            justify-content: space-between;\n            align-items: center;\n            flex-wrap: wrap;\n            gap: 1rem;\n        }}\n\n        .host-info {{\n            display: flex;\n            align-items: center;\n            gap: 0.75rem;\n        }}\n\n        .host-icon {{\n            color: #6366f1;\n        }}\n\n        .host-header h3 {{\n            font-size: 1.25rem;\n            font-weight: 600;\n        }}\n\n        .hostname {{\n            font-weight: 400;\n            font-size: 0.95rem;\n            color: var(--text-muted);\n        }}\n\n        .os-badge {{\n            background-color: rgba(99, 102, 241, 0.15);\n            color: #a5b4fc;\n            font-size: 0.75rem;\n            padding: 0.25rem 0.75rem;\n            border-radius: 20px;\n            font-weight: 500;\n        }}\n\n        /* Tables */\n        .table-container {{\n            width: 100%;\n            overflow-x: auto;\n        }}\n\n        table {{\n            width: 100%;\n            border-collapse: collapse;\n            text-align: left;\n            font-size: 0.925rem;\n        }}\n\n        th {{\n            background-color: rgba(0, 0, 0, 0.15);\n            color: var(--text-muted);\n            font-weight: 500;\n            padding: 1rem 1.5rem;\n            font-size: 0.8rem;\n            text-transform: uppercase;\n            letter-spacing: 0.05em;\n            border-bottom: 1px solid var(--card-border);\n        }}\n\n        td {{\n            padding: 1rem 1.5rem;\n            border-bottom: 1px solid var(--card-border);\n            color: var(--text-main);\n            vertical-align: middle;\n        }}\n\n        .port-row:hover {{\n            background-color: rgba(255, 255, 255, 0.01);\n        }}\n\n        .port-number {{\n            font-family: var(--font-mono);\n            font-weight: 600;\n            color: #fff;\n        }}\n\n        .service-name {{\n            font-family: var(--font-mono);\n            font-size: 0.875rem;\n        }}\n\n        /* Badges */\n        .proto-badge {{\n            font-family: var(--font-mono);\n            font-size: 0.75rem;\n            padding: 0.15rem 0.4rem;\n            border-radius: 4px;\n            text-transform: uppercase;\n            font-weight: 500;\n        }}\n\n        .proto-badge.tcp {{\n            background-color: rgba(59, 130, 246, 0.12);\n            color: #93c5fd;\n        }}\n\n        .proto-badge.udp {{\n            background-color: rgba(168, 85, 247, 0.12);\n            color: #d8b4fe;\n        }}\n\n        .status-badge {{\n            font-size: 0.75rem;\n            font-weight: 600;\n            text-transform: uppercase;\n            padding: 0.2rem 0.5rem;\n            border-radius: 6px;\n            letter-spacing: 0.025em;\n            display: inline-block;\n        }}\n\n        .status-badge.open {{\n            background-color: var(--open-bg);\n            color: var(--open-color);\n        }}\n\n        .conf-badge {{\n            font-size: 0.8rem;\n            font-weight: 500;\n            font-family: var(--font-mono);\n            padding: 0.15rem 0.4rem;\n            border-radius: 4px;\n        }}\n\n        .conf-high {{\n            background-color: rgba(16, 185, 129, 0.15);\n            color: #34d399;\n        }}\n\n        .conf-medium {{\n            background-color: rgba(245, 158, 11, 0.15);\n            color: #fbbf24;\n        }}\n\n        .conf-low {{\n            background-color: rgba(239, 68, 68, 0.15);\n            color: #fca5a5;\n        }}\n\n        .empty-state {{\n            text-align: center;\n            color: var(--text-muted);\n            padding: 3rem !important;\n            font-style: italic;\n        }}\n\n        /* TLS Detail Card */\n        .tls-row td {{\n            padding-top: 0;\n            padding-bottom: 1rem;\n            background-color: rgba(0, 0, 0, 0.05);\n        }}\n\n        .tls-card {{\n            background-color: rgba(255, 255, 255, 0.02);\n            border: 1px dashed var(--card-border);\n            border-radius: 8px;\n            padding: 1rem;\n            font-size: 0.85rem;\n            margin-top: 0.25rem;\n        }}\n\n        .tls-title {{\n            color: #38bdf8;\n            font-weight: 600;\n            margin-bottom: 0.5rem;\n            display: flex;\n            align-items: center;\n            gap: 0.4rem;\n        }}\n\n        .tls-grid {{\n            display: grid;\n            grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));\n            gap: 0.5rem 1.5rem;\n        }}\n\n        .tls-full-width {{\n            grid-column: 1 / -1;\n            word-break: break-all;\n        }}\n\n        /* Footer */\n        footer {{\n            margin-top: 5rem;\n            text-align: center;\n            color: var(--text-muted);\n            font-size: 0.8rem;\n            padding: 2rem 0;\n            border-top: 1px solid var(--card-border);\n        }}\n    </style>\n</head>\n<body>\n    <div class="container">\n        <header>\n            <div class="brand-section">\n                <div class="logo">\n                    <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z"></path></svg>\n                </div>\n                <div class="brand-name">\n                    <h1>NetProbe</h1>\n                    <span>v{report.scanner_version} — SECURITY AUDIT</span>\n                </div>\n            </div>\n            <div class="meta-info">\n                <p>Run: <code>{report.command_line or 'cli'}</code></p>\n                <p style="margin-top: 0.25rem;">Completed: {(report.end_time.astimezone(timezone.utc).strftime('%Y-%m-%d %H:%M:%S UTC') if report.end_time else 'N/A')}</p>\n            </div>\n        </header>\n\n        <section class="overview-grid">\n            <div class="card stat-card">\n                <span class="stat-label">Total Targets</span>\n                <span class="stat-value">{total_hosts}</span>\n                <span class="stat-desc">IP addresses parsed</span>\n            </div>\n            <div class="card stat-card">\n                <span class="stat-label">Active Hosts</span>\n                <span class="stat-value">{active_hosts}</span>\n                <span class="stat-desc">Hosts with open ports</span>\n            </div>\n            <div class="card stat-card">\n                <span class="stat-label">Open Ports</span>\n                <span class="stat-value">{total_open_ports}</span>\n                <span class="stat-desc">Total open ports discovered</span>\n            </div>\n            <div class="card stat-card">\n                <span class="stat-label">Duration</span>\n                <span class="stat-value">{report.duration:.2f}s</span>\n                <span class="stat-desc">Scan execution time</span>\n            </div>\n        </section>\n\n        <section class="hosts-section">\n            {hosts_html}\n        </section>\n\n        <footer>\n            <p>NetProbe is intended solely for authorized penetration testing, security auditing, and educational environments.</p>\n            <p style="margin-top: 0.5rem;">Confidential Report. Generated on {datetime.now(timezone.utc).strftime('%Y-%m-%d %H:%M:%S UTC')}</p>\n        </footer>\n    </div>\n</body>\n</html>\n"""
